ion'+ temp_p).append("<option value='0'>ohne</option>");				jQuery('#Progression'+ temp_p).append("<option value='225'>mind. 225%</option>");				jQuery('#Progression'+ temp_p).append("<option value='300'>mind. 300%</option>");				jQuery('#Progression'+ temp_p).append("<option value='350'>mind. 350%</option>");				jQuery('#Progression'+ temp_p).append("<option value='400'>mind. 400%</option>");				jQuery('#Progression'+ temp_p).append("<option value='500'>mind. 500%</option>");				jQuery('#Progression'+ temp_p).append("<option value='600'>mind. 600%</option>");				jQuery('#Progression'+ temp_p).append("<option value='1000'>mind. 1000%</option>");				jQuery('#Progression'+ temp_p).val($('#Progression' +temp_p +' option:first').val());				//costmetic operation				jQuery('#Operationenview'+ temp_p).attr('style', 'display:block');				//salvage costs				jQuery('#Bergungskostenview'+ temp_p).attr('style', 'display:block');				//transition benefit				jQuery('#Uebergangsleistungview'+ temp_p).attr('style', 'display:block');			}		}		initial = '1';	}};function set_val_for_edhp(){	if(jQuery("#is_edhp").length && jQuery('#backbutton_false').length && jQuery('#backbutton_false').val() == '1'){		$('input:radio[name="Geschlecht"]').filter('[value="0"]').attr('checked', true);		jQuery('#Todesfallsumme').val('10000');		jQuery('#Risikogruppe option[value="A"]').attr("selected", "selected");	}};function set_OAB_values(){	jQuery("#tgru").val('0');	jQuery("#ergebnisausgabe").val('B');	jQuery('#Invaliditaetssumme').val('0');	jQuery('#ZAHLWEISE').val($('#ZAHLWEISE option:first').val());		//set new values for OAB		if(jQuery('#PersonenAnzahl').val())			var p = jQuery('#PersonenAnzahl').val();		else			var p = 1;		for(j = 1; j <= p; ++j) {			if(j === 1)				temp_p = '';			else				temp_p = j;			//progression select			jQuery('#Progression'+ temp_p).empty();			jQuery('#Progression'+ temp_p).append("<option value='0'>ohne</option>");			jQuery('#Progression'+ temp_p).append("<option value='225'>mind. 225%</option>");			jQuery('#Progression'+ temp_p).append("<option value='350'>mind. 350%</option>");			jQuery('#Progression'+ temp_p).append("<option value='500'>mind. 500%</option>");			jQuery('#Progression' +temp_p +' option[value="225"]').attr("selected", "selected");			jQuery('#Uebergangsleistung'+ temp_p).val('0');	}};</script><script type="text/javascript">	function SmallWindow71(wintype) {		SmallWin71=window.open(wintype,"SmallWin71","toolbar=no,directories=no,status=no,scrollbars=yes,menubar=yes,width=415,height=200"); SmallWin71.window.focus()	}	function SmallWindow40(wintype) {		SmallWin40=window.open(wintype,"SmallWin40","toolbar=yes,directories=no,status=no,scrollbars=yes,menubar=yes,width=620,height=490"); SmallWin40.window.focus()	}/*	function btn() {		jQuery('.btnNext').click(function(){		jQuery('.nav-tabs > .active').next('li').find('a').trigger('click')		});		jQuery('.btnPrevious').click(function(){		jQuery('.nav-tabs > .active').prev('li').find('a').trigger('click');		});	}*/	function show_previous_tab() {		var prev = $( '#tab li.active' ).prev();		while ( prev.hasClass( 'hide' ) ) {	prev = prev.prev() }		$('body').animate( { scrollTop: 0 }, 'fast', function() { prev.find( 'a' ).tab( 'show' ) } );		return false;	};	function show_next_tab() {		var next = $( '#tab li.active' ).next();		while ( next.hasClass( 'hide' ) ) {	next = next.next() }		$('body').animate( { scrollTop: 0 }, 'fast', function() { next.find( 'a' ).tab( 'show' ) } );		return false;	};	function emptyVBeginn() {		$('#VBEGINN').val("");		$('#inputForm').data('formValidation').enableFieldValidators( 'VBEGINN', true ).revalidateField('VBEGINN');	}	function emptyDATUM() {		$('#DATUM').val("");		$('#inputForm').data('formValidation').enableFieldValidators( 'DATUM', true ).revalidateField('DATUM');	}	function emptyDATUM2() {		$('#DATUM2').val("");		$('#inputForm').data('formVali