ing(2,4);			var jjjj 	= Datum.substring(4,6);			if ( jjjj < 20 ) {				var jahrhundert = 20;			} else {				var jahrhundert = 19;			}		}	}};</script><script type="text/javascript">    window.onload = function(event)    {        set_val_for_edhp();    personen();    setTomorrow();    check_vermittlererstinfo();    tggt(1);    tggt(2);    tggt(3);    tggt(4);    tggt(5);    tggt(6);    khgt(1);    khgt(2);    khgt(3);    khgt(4);    khgt(5);    khgt(6);    }</script></head><BODY BGCOLOR="#blue"   onpageshow="reValidateForm()"><br>
